-- ============================================================
-- SpO₂
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('spo2','id-ID','SpO₂','Mengukur saturasi oksigen dalam darah — persentase hemoglobin yang terikat oksigen.','SpO₂ (Saturation of Peripheral Oxygen) mengukur seberapa banyak oksigen dibawa oleh sel darah merah. Nilai ini penting untuk menilai fungsi paru dan jantung. SpO₂ diukur non-invasif melalui sensor cahaya di ujung jari.','Mendeteksi hipoksemia dini sebelum gejala klinis muncul. Penting untuk pasien PPOK, asma, sleep apnea, pasca-COVID, dan kondisi jantung.','Duduk tenang 5 menit. Tangan hangat, tidak bersikat. Sensor di jari telunjuk, tangan setinggi dada. Hindari kutek/cat kuku. Baca setelah angka stabil ±10 detik.','95–100% (dewasa di atas permukaan laut)','Persen (%) = jumlah oksigen terikat per 100 molekul hemoglobin. 97% artinya dari 100 molekul Hb, 97 membawa oksigen.','Oximeter','oximeter','SpO₂ <90%: hipoksemia berat → risiko gagal organ, kerusakan otak. Kronis: pulmonary hypertension, right heart failure.','SpO₂ <92% saat istirahat atau <88% saat aktivitas → segera ke IGD. Perokok: nilai bisa normal meskipun ada COPD (carboxyhemoglobin).','Berhenti merokok. Olahraga teratur untuk kapasitas paru. Vaksinasi influenza dan pneumokokus setiap tahun. Cek SpO₂ jika sesak napas.','WHO Pulse Oximetry Training Manual 2011; ATS Patient Education 2019','https://www.who.int/publications/i/item/9789241501547'),
('spo2','en-US','SpO₂','Measures blood oxygen saturation — the percentage of hemoglobin bound with oxygen.','SpO₂ (Saturation of Peripheral Oxygen) measures how much oxygen is carried by red blood cells. It is vital for assessing lung and heart function. Measured non-invasively via a light sensor on the fingertip.','Detects hypoxemia early before clinical symptoms appear. Essential for COPD, asthma, sleep apnea, post-COVID, and cardiac patients.','Sit quietly for 5 minutes. Warm hands, no nail polish. Sensor on index finger at chest level. Read after number stabilizes for ~10 seconds.','95–100% (adults at sea level)','Percent (%) = molecules of oxygen bound per 100 hemoglobin molecules. 97% means 97 out of 100 Hb molecules carry oxygen.','Pulse Oximeter','oximeter','SpO₂ <90%: severe hypoxemia → organ failure, brain damage risk. Chronic: pulmonary hypertension, right heart failure.','SpO₂ <92% at rest or <88% with exertion → go to ER immediately. Smokers: readings may be falsely normal due to carboxyhemoglobin.','Quit smoking. Exercise regularly for lung capacity. Annual influenza and pneumococcal vaccination. Check SpO₂ if short of breath.','WHO Pulse Oximetry Training Manual 2011; ATS Patient Education 2019','https://www.who.int/publications/i/item/9789241501547');

-- ============================================================
-- Heart Rate
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('heartRate','id-ID','Denyut Jantung','Menghitung jumlah detak jantung per menit — indikator fungsi kardiovaskular dasar.','Denyut jantung (heart rate / pulse) adalah frekuensi kontraksi ventrikel per menit. Mencerminkan kerja jantung, regulasi otonom, dan kebugaran kardiovaskular. Denyut jantung istirahat yang rendah umumnya menandakan kebugaran baik.','Mendeteksi aritmia (fibrilasi atrium, takikardia, bradikardia). Memantau respons obat (beta-blocker, digoxin). Menilai kebugaran dan overtraining.','Duduk/berbaring 5 menit sebelum ukur. Hitung denyut selama 60 detik di nadi radial, atau pakai oximeter/tensimeter. Hindari kafein/rokok 30 menit sebelumnya.','60–100 bpm (dewasa istirahat). Atlet terlatih: 40–60 bpm normal.','bpm = beats per minute (denyut per menit). Menunjukkan seberapa sering jantung berdenyut dalam 1 menit.','Oximeter / Tensimeter','oximeter','Takikardia kronis (>100): risiko stroke, heart failure, takikardiomiopati. Bradikardia (<40 tanpa latihan): sinkope, gagal jantung.','Denyut >150 saat istirahat, <40 tanpa olahraga teratur, atau tidak beraturan (AFib) → segera ke dokter. Gejala: pusing, sesak, nyeri dada.','Olahraga kardio 150 menit/minggu. Batasi kafein <400 mg/hari. Tidur cukup 7–9 jam. Kelola stres. Hindari rokok dan alkohol berlebihan.','AHA Understanding Heart Rate 2023; Mayo Clinic','https://www.heart.org/en/health-topics/high-blood-pressure/the-facts-about-high-blood-pressure/all-about-heart-rate-pulse'),
('heartRate','en-US','Heart Rate','Counts the number of heartbeats per minute — a basic cardiovascular function indicator.','Heart rate (pulse) is the frequency of ventricular contractions per minute. It reflects cardiac workload, autonomic regulation, and cardiovascular fitness. Lower resting heart rate generally indicates better fitness.','Detects arrhythmia (atrial fibrillation, tachycardia, bradycardia). Monitors drug effects (beta-blockers, digoxin). Assesses fitness and overtraining.','Sit/lie down for 5 minutes before measuring. Count pulse for 60 seconds at radial artery, or use oximeter/BP monitor. Avoid caffeine/smoking 30 minutes prior.','60–100 bpm (resting adult). Trained athletes: 40–60 bpm is normal.','bpm = beats per minute. Shows how often the heart beats in 1 minute.','Pulse Oximeter / BP Monitor','oximeter','Chronic tachycardia (>100): stroke, heart failure, tachycardiomyopathy risk. Bradycardia (<40 without training): syncope, heart failure.','HR >150 at rest, <40 without regular exercise, or irregular (AFib) → see doctor immediately. Symptoms: dizziness, shortness of breath, chest pain.','150 min/week cardio exercise. Limit caffeine <400 mg/day. Sleep 7–9 hours. Manage stress. Avoid smoking and excess alcohol.','AHA Understanding Heart Rate 2023; Mayo Clinic','https://www.heart.org/en/health-topics/high-blood-pressure/the-facts-about-high-blood-pressure/all-about-heart-rate-pulse');

-- ============================================================
-- Systolic
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('systolic','id-ID','Tekanan Sistolik','Tekanan darah saat jantung berkontraksi memompa darah ke seluruh tubuh.','Tekanan sistolik adalah tekanan puncak saat ventrikel kiri berkontraksi. Angka ini lebih prediktif terhadap risiko kardiovaskular daripada diastolik, khususnya pada usia >50 tahun (AHA 2017).','Hipertensi adalah silent killer — sering tanpa gejala. Deteksi dini mencegah stroke, serangan jantung, gagal ginjal. Target <130/80 untuk diabetes/CKD (ADA 2023).','Duduk tegak 5 menit. Lengan setinggi jantung. Cuff melingkar rapat di lengan atas. Ukur 2x, ambil rata-rata. Jangan habis kopi/rokok 30 menit sebelumnya.','<120 mmHg = normal; 120–129 = elevated; 130–139 = hipertensi stage 1; ≥140 = hipertensi stage 2 (AHA 2017)','mmHg = millimeter of mercury. 1 mmHg ≈ tekanan 1,36 cmH₂O. Menunjukkan gaya darah pada dinding arteri saat jantung memompa.','Tensimeter','bloodPressure','Sistolik ≥140: risiko stroke 4× lipat, serangan jantung 3× lipat, gagal ginjal kronis. Sistolik >180: krisis hipertensi → kerusakan organ.','Sistolik ≥180 atau <90 dengan gejala (sakit kepala berat, penglihatan kabur, nyeri dada, sesak) → IGD. Sistolik ≥140 tanpa gejala: kontrol ke dokter dalam 1 bulan.','Limit garam <5 g/hari (WHO). Olahraga 150 menit/minggu. Turunkan berat badan jika BMI >25. Batasi alkohol. Kelola stres. Minum obat hipertensi teratur.','AHA 2017 Hypertension Guidelines (Whelton et al.); WHO HEARTS Technical Package','https://www.heart.org/en/health-topics/high-blood-pressure/understanding-blood-pressure-readings'),
('systolic','en-US','Systolic Pressure','Blood pressure when the heart contracts and pumps blood throughout the body.','Systolic pressure is the peak pressure during left ventricular contraction. It is more predictive of cardiovascular risk than diastolic, especially in adults >50 years (AHA 2017).','Hypertension is a silent killer — often asymptomatic. Early detection prevents stroke, heart attack, kidney failure. Target <130/80 for diabetes/CKD (ADA 2023).','Sit upright for 5 minutes. Arm at heart level. Cuff snug around upper arm. Measure twice, take average. No coffee/smoking 30 minutes prior.','<120 mmHg = normal; 120–129 = elevated; 130–139 = hypertension stage 1; ≥140 = hypertension stage 2 (AHA 2017)','mmHg = millimeters of mercury. 1 mmHg ≈ 1.36 cmH₂O pressure. Indicates force of blood on artery walls when the heart pumps.','Blood Pressure Monitor','bloodPressure','Systolic ≥140: 4× stroke risk, 3× heart attack risk, chronic kidney failure. Systolic >180: hypertensive crisis → organ damage.','Systolic ≥180 or <90 with symptoms (severe headache, blurred vision, chest pain, shortness of breath) → go to ER. Systolic ≥140 without symptoms: see doctor within 1 month.','Limit salt <5 g/day (WHO). Exercise 150 min/week. Lose weight if BMI >25. Limit alcohol. Manage stress. Take hypertension medication regularly.','AHA 2017 Hypertension Guidelines (Whelton et al.); WHO HEARTS Technical Package','https://www.heart.org/en/health-topics/high-blood-pressure/understanding-blood-pressure-readings');

-- ============================================================
-- Diastolic
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('diastolic','id-ID','Tekanan Diastolik','Tekanan darah saat jantung beristirahat (diastole) antar detikan.','Tekanan diastolik adalah tekanan minimum pada arteri saat jantung mengisi darah. Diastolik tinggi kronis menyebabkan kerusakan pembuluh darah kecil, terutama di ginjal dan otak (NHLBI).','Diastolik tinggi pada usia muda (<50 thn) sama prediktifnya dengan sistolik tinggi terhadap risiko kardiovaskular. Penting untuk skrining hipertensi di usia produktif.','Cara ukur sama dengan sistolik — diukur bersamaan menggunakan tensimeter. Angka bawah dari pembacaan (mis. 120/80 → diastolik = 80).','<80 mmHg = normal; 80–89 = hipertensi stage 1; ≥90 = hipertensi stage 2 (AHA 2017)','mmHg = millimeter raksa. Menunjukkan tekanan minimum di arteri saat jantung istirahat antar detik.','Tensimeter','bloodPressure','Diastolik ≥90 kronis: hipertrofi ventrikel kiri, penyakit ginjal kronis, retinopati hipertensi. Diastolik >120: krisis hipertensi.','Diastolik >120 → segera ke IGD. Diastolik ≥90 + sakit kepala/nystagmus/nosebleed → dokter hari ini. Diastolik ≥80 tanpa gejala: kontrol 3 bulan.','Kurangi garam, proses makanan kalengan/minuman bersoda. Tidur cukup. Jaga berat badan ideal. Cek tekanan darah 6 bulan sekali.','AHA 2017 Hypertension Guidelines; NHLBI/NIH','https://www.heart.org/en/health-topics/high-blood-pressure/understanding-blood-pressure-readings'),
('diastolic','en-US','Diastolic Pressure','Blood pressure when the heart rests (diastole) between beats.','Diastolic pressure is the minimum pressure in arteries when the heart fills with blood. Chronic high diastolic damages small blood vessels, particularly in kidneys and brain (NHLBI).','High diastolic in younger adults (<50 yr) is equally predictive of cardiovascular risk as high systolic. Important for hypertension screening in working-age adults.','Measured simultaneously with systolic using a BP monitor. The lower number in the reading (e.g., 120/80 → diastolic = 80).','<80 mmHg = normal; 80–89 = hypertension stage 1; ≥90 = hypertension stage 2 (AHA 2017)','mmHg = millimeters of mercury. Indicates minimum pressure in arteries when the heart rests between beats.','Blood Pressure Monitor','bloodPressure','Diastolic ≥90 chronic: left ventricular hypertrophy, chronic kidney disease, hypertensive retinopathy. Diastolic >120: hypertensive crisis.','Diastolic >120 → go to ER immediately. Diastolic ≥90 + headache/nystagmus/nosebleed → see doctor today. Diastolic ≥80 without symptoms: check in 3 months.','Reduce salt, avoid canned/processed food and soda. Adequate sleep. Maintain ideal weight. Check blood pressure every 6 months.','AHA 2017 Hypertension Guidelines; NHLBI/NIH','https://www.heart.org/en/health-topics/high-blood-pressure/understanding-blood-pressure-readings');

-- ============================================================
-- bloodPressurePulse
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('bloodPressurePulse','id-ID','Pulse Tensimeter','Denyut nadi terbaca oleh tensimeter selama pengukuran tekanan darah.','Pulse tensimeter adalah denyut nadi yang terdeteksi alat saat cuff mengembang dan kempes. Berbeda dari pulse oximeter — ini membaca osilasi dinding arteri, bukan absorpsi cahaya. Berguna untuk cross-check denyut jantung.','Memvalidasi denyut jantung yang terbaca oximeter. Mendeteksi aritmia (jika pulse BP berbeda signifikan dari pulse oximeter → kemungkinan AFib atau PVC).','Otomatis terukur saat tensimeter bekerja. Cocokkan dengan pulse oximeter: jika beda >10 bpm, ulangi pengukuran dan konsultasi dokter.','60–100 bpm (harus konsisten dengan oximeter ±5 bpm)','bpm = denyut per menit via osilasi arteri brachialis. Diukur bersamaan dengan tekanan darah oleh tensimeter digital.','Tensimeter','bloodPressure','Discrepancy >10 bpm dengan oximeter → kemungkinan irregular heartbeat/AFib. Pulse >100 saat istirahat: takikardia.','Jika pulse tensimeter berbeda >15 bpm dari oximeter, atau pulse >120/<40 saat istirahat → periksa EKG ke dokter.','Jaga kebugaran kardiovaskular. Deteksi dini AFib dengan pemantauan rutin. Kurangi stres dan kafein berlebihan.','AHA Understanding Heart Rate; European Heart Rhythm Association 2023','https://www.heart.org/en/health-topics/high-blood-pressure/the-facts-about-high-blood-pressure/all-about-heart-rate-pulse'),
('bloodPressurePulse','en-US','BP Monitor Pulse','Heart rate detected by the blood pressure monitor during measurement.','BP monitor pulse is the heart rate detected by the device as the cuff inflates and deflates. It differs from pulse oximetry — it reads arterial wall oscillations, not light absorption. Useful for cross-checking heart rate.','Validates heart rate from the oximeter. Detects arrhythmia (if BP pulse differs significantly from oximeter pulse → possible AFib or PVC).','Automatically measured when the BP monitor operates. Cross-check with oximeter: if difference >10 bpm, repeat measurement and consult a doctor.','60–100 bpm (should be consistent with oximeter ±5 bpm)','bpm = beats per minute via brachial artery oscillations. Measured simultaneously with blood pressure by digital BP monitor.','Blood Pressure Monitor','bloodPressure','Discrepancy >10 bpm with oximeter → possible irregular heartbeat/AFib. Pulse >100 at rest: tachycardia.','If BP pulse differs >15 bpm from oximeter, or pulse >120/<40 at rest → get ECG from doctor.','Maintain cardiovascular fitness. Early AFib detection with regular monitoring. Reduce stress and excess caffeine.','AHA Understanding Heart Rate; European Heart Rhythm Association 2023','https://www.heart.org/en/health-topics/high-blood-pressure/the-facts-about-high-blood-pressure/all-about-heart-rate-pulse');

