-- glucoseFasting
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('glucoseFasting','id-ID','Gula Darah Puasa','Kadar glukosa darah setelah puasa 8–12 jam — standar emas skrining diabetes.','Gula darah puasa (Fasting Plasma Glucose / FPG) mengukur glukosa setelah tidak makan minimal 8 jam. Merupakan tes skrining utama diabetes melitus tipe 2 (ADA Standards of Care 2023). Lebih akurat daripada gula darah acak.','Mendeteksi prediabetes dan diabetes dini. 1 dari 3 penderita diabetes tidak tahu mereka terkena (IDF 2023). Semakin dini terdeteksi, semakin efektif pencegahan komplikasi.','Puasa 8–12 jam (hanya air putih). Ukur sebelum makan pagi, idealnya 06.00–09.00. Cuci tangan sebelum tes (sisa makanan di jari bisa mempengaruhi). Gunakan strip yang tidak kedaluwarsa.','70–99 mg/dL = normal; 100–125 = prediabetes; ≥126 = diabetes (ADA 2023)','mg/dL = miligram glukosa per desiliter darah. 100 mg/dL = 100 mg gula dalam 1/10 liter darah. Puasa 8–12 jam memastikan kadar basal, bukan pasca-makan.','GCU (Sinocare)','sinocare','Prediabetes (100–125): 5–10% per tahun berkembang jadi diabetes. Diabetes: retinopati, nefropati, neuropati, penyakit jantung 2–4× lipat.','Gula darah puasa ≥126 mg/dL pada 2 kali tes → diagnosis diabetes → ke dokter. ≥200 mg/dL: segera ke dokter. <70: hipoglikemia → minum jus.','Jaga berat badan ideal. Makanan rendah glikemik index. Olahraga 150 menit/minggu (terbukti turunkan risiko diabetes 58% — DPP study). Hindari minuman manis.','ADA Standards of Medical Care in Diabetes 2023; IDF Diabetes Atlas 2023','https://diabetesjournals.org/care/article/46/Supplement_1/S1/127039/Summary-of-Updates-Standards-of-Care-in-Diabetes'),
('glucoseFasting','en-US','Fasting Blood Glucose','Blood glucose level after fasting 8–12 hours — the gold standard for diabetes screening.','Fasting Plasma Glucose (FPG) measures glucose after not eating for at least 8 hours. It is the primary screening test for type 2 diabetes mellitus (ADA Standards of Care 2023). More accurate than random glucose.','Detects prediabetes and early diabetes. 1 in 3 people with diabetes do not know they have it (IDF 2023). Earlier detection means more effective complication prevention.','Fast 8–12 hours (water only). Measure before breakfast, ideally 6–9 AM. Wash hands before testing (food residue on fingers can affect). Use non-expired strips.','70–99 mg/dL = normal; 100–125 = prediabetes; ≥126 = diabetes (ADA 2023)','mg/dL = milligrams of glucose per deciliter of blood. 100 mg/dL = 100 mg sugar in 1/10 liter of blood. 8–12 hour fasting ensures basal level, not post-meal.','GCU (Sinocare)','sinocare','Prediabetes (100–125): 5–10% per year progress to diabetes. Diabetes: retinopathy, nephropathy, neuropathy, 2–4× heart disease risk.','Fasting glucose ≥126 mg/dL on 2 tests → diabetes diagnosis → see doctor. ≥200 mg/dL: see doctor immediately. <70: hypoglycemia → drink juice.','Maintain ideal weight. Low glycemic index diet. Exercise 150 min/week (proven 58% diabetes risk reduction — DPP study). Avoid sugary drinks.','ADA Standards of Medical Care in Diabetes 2023; IDF Diabetes Atlas 2023','https://diabetesjournals.org/care/article/46/Supplement_1/S1/127039/Summary-of-Updates-Standards-of-Care-in-Diabetes');

-- ============================================================
-- glucosePostMeal
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('glucosePostMeal','id-ID','Gula Darah 2 Jam PP','Kadar glukosa darah 2 jam setelah makan — mengevaluasi respons glikemik.','Gula darah post-prandial (PP) diukur 2 jam setelah makan pertama (dihitung dari awal makan). Merupakan indikator sensitivitas insulin dan toleransi glukosa. ADA 2023: PP ≥200 mg/dL = diabetes.','FPG bisa normal tapi PP tinggi → diabetes terlewat. 30% penderita diabetes hanya terdeteksi lewat tes PP. Penting untuk skrining lengkap dan evaluasi pengobatan.','Ukur tepat 2 jam setelah mulai makan (bukan selesai makan). Makan normal (minimal 75g karbohidrat). Catat waktu mulai makan. Jangan ngemil di antara.','<140 mg/dL = normal; 140–199 = intoleransi glukosa; ≥200 = diabetes (ADA 2023)','mg/dL = miligram glukosa per desiliter darah. Mengukur respons tubuh terhadap asupan karbohidrat. 2 jam PP = saat glukosa seharusnya kembali mendekati baseline.','GCU (Sinocare)','sinocare','PP kronis ≥200: kerusakan pembuluh darah mikro (mata, ginjal, saraf). Risiko kardiovaskular meningkat bahkan di 140–199.','PP ≥200 mg/dL → diagnosis diabetes. PP 140–199 berkali-kali → prediabetes, diskusikan dokter. PP ≥300: bisa terjadi ketoasidosis.','Makan porsi kecil sering (3 besar + 2 selingan). Karbohidrat kompleks lebih baik dari sederhana. Jalan kaki 15 menit setelah makan turunkan PP 30%.','ADA Standards of Care 2023; WHO Definition and Diagnosis of Diabetes','https://diabetesjournals.org/care/article/46/Supplement_1/S1/127039/Summary-of-Updates-Standards-of-Care-in-Diabetes'),
('glucosePostMeal','en-US','Post-Meal Blood Glucose','Blood glucose 2 hours after eating — evaluates glycemic response.','Post-prandial (PP) glucose is measured 2 hours after the first bite of a meal. It indicates insulin sensitivity and glucose tolerance. ADA 2023: PP ≥200 mg/dL = diabetes.','FPG may be normal but PP elevated → diabetes missed. 30% of diabetes cases are detected only through PP testing. Essential for comprehensive screening and treatment evaluation.','Measure exactly 2 hours after starting to eat (not after finishing). Eat a normal meal (at least 75g carbohydrates). Note the time you started eating. No snacking in between.','<140 mg/dL = normal; 140–199 = impaired glucose tolerance; ≥200 = diabetes (ADA 2023)','mg/dL = milligrams glucose per deciliter of blood. Measures the body''s response to carbohydrate intake. 2hr PP = when glucose should return near baseline.','GCU (Sinocare)','sinocare','Chronic PP ≥200: microvascular damage (eyes, kidneys, nerves). Cardiovascular risk increases even at 140–199.','PP ≥200 mg/dL → diabetes diagnosis. PP 140–199 repeatedly → prediabetes, discuss with doctor. PP ≥300: risk of ketoacidosis.','Eat small frequent meals (3 main + 2 snacks). Complex carbs better than simple. Walk 15 minutes after meals to reduce PP by 30%.','ADA Standards of Care 2023; WHO Definition and Diagnosis of Diabetes','https://diabetesjournals.org/care/article/46/Supplement_1/S1/127039/Summary-of-Updates-Standards-of-Care-in-Diabetes');

-- ============================================================
-- cholesterolTotal
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('cholesterolTotal','id-ID','Kolesterol Total','Jumlah keseluruhan kolesterol dalam darah termasuk LDL, HDL, dan VLDL.','Kolesterol total adalah penjumlahan LDL (jahat), HDL (baik), dan VLDL. Sendiri bukan diagnosis — harus dipisahkan LDL dan HDL. Tapi sebagai skrining awal, nilai >200 menandakan perlu lipid panel lengkap (AHA/ACC 2018).','Kolesterol tinggi tidak bergejala. Plak aterosklerosis terbentuk puluhan tahun sebelum serangan jantung. Skrining setiap 5 tahun mulai usia 20 (AHA 2018).','Puasa 9–12 jam (air putih boleh). Gunakan alat point-of-care (Sinocare GCU) atau tes laboratorium. Ukur di pagi hari. Hindari olahraga berat 24 jam sebelumnya.','<200 mg/dL = diinginkan; 200–239 = borderline; ≥240 = tinggi (AHA/ACC 2018)','mg/dL = miligram kolesterol per desiliter darah. Kolesterol adalah lemak darah — dibutuhkan sel, tapi berlebih menumpuk di dinding arteri.','GCU (Sinocare)','sinocare','Total ≥240: risiko CHD 2× lipat. Aterosklerosis → serangan jantung, stroke. Plak bisa rupture → trombosis akut.','Total ≥240 atau LDL ≥160 → konsultasi dokter untuk lipid panel lengkap dan pertimbangan statin. Usia >40 + diabetes: statin indikasi.','Kurangi lemak jenuh (daging merah, mentega, kelapa). Makan serat larut (oat, kacang, buah). Olahraga naikkan HDL. Berhenti merokok naikkan HDL 10%.','AHA/ACC 2018 Cholesterol Guidelines; ATP III/NHLBI','https://www.heart.org/en/health-topics/cholesterol'),
('cholesterolTotal','en-US','Total Cholesterol','Total amount of cholesterol in blood including LDL, HDL, and VLDL.','Total cholesterol is the sum of LDL (bad), HDL (good), and VLDL. Alone it is not diagnostic — LDL and HDL must be separated. But as initial screening, >200 signals the need for a full lipid panel (AHA/ACC 2018).','High cholesterol is asymptomatic. Atherosclerotic plaque builds over decades before a heart attack. Screen every 5 years starting at age 20 (AHA 2018).','Fast 9–12 hours (water allowed). Use point-of-care device (Sinocare GCU) or lab test. Measure in the morning. Avoid heavy exercise 24 hours prior.','<200 mg/dL = desirable; 200–239 = borderline; ≥240 = high (AHA/ACC 2018)','mg/dL = milligrams cholesterol per deciliter of blood. Cholesterol is a blood fat — cells need it, but excess deposits on artery walls.','GCU (Sinocare)','sinocare','Total ≥240: 2× CHD risk. Atherosclerosis → heart attack, stroke. Plaque can rupture → acute thrombosis.','Total ≥240 or LDL ≥160 → consult doctor for full lipid panel and possible statin therapy. Age >40 + diabetes: statin indicated.','Reduce saturated fat (red meat, butter, coconut). Eat soluble fiber (oats, beans, fruit). Exercise raises HDL. Quit smoking to raise HDL by 10%.','AHA/ACC 2018 Cholesterol Guidelines; ATP III/NHLBI','https://www.heart.org/en/health-topics/cholesterol');

