INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('uricAcid','id-ID','Asam Urat','Produk akhir metabolisme purin — kadar tinggi menyebabkan gout dan batu ginjal.','Asam urat dibentuk dari pemecahan purin (senyawa di daging, ikan, alkohol). Ginjal membuang 70%. Kelebihan (hiperurisemia) mengkristal di sendi → gout, atau di ginjal → batu ginjal. Prevalensi gout di Indonesia 1–3% (EAU 2024).','Gout sering tidak terdiagnosis. Hiperurisemia kronis juga berkaitan dengan hipertensi, metabolic syndrome, dan penyakit ginjal kronis (MEGA study, ARA 2020).','Puasa 4 jam. Tes darah vena atau GCU point-of-care. Hindarkan makanan tinggi purin 24 jam sebelum tes (jeroan, kerang, bir). Minum air putih cukup 2L/hari sebelum tes.','Pria: <7 mg/dL; Wanita: <6 mg/dL (ACR/EULAR 2020)','mg/dL = miligram asam urat per desiliter darah. Nilai >7 = supersaturasi → kristal monosodium urat bisa terbentuk.','GCU (Sinocare)','sinocare','>7 mg/dL kronis: gout arthritis rekuren, tofi, batu ginjal urat (10–25%). Gout: risiko CKD dan kardiovaskular meningkat.','≥8 mg/dL + nyeri sendi (terutama ibu jari kaki) → reumatologis. ≥9 mg/dL tanpa gejala: diskusikan terapi urat-lowering. Batu ginjal + asam urat tinggi: urologi.','Minum air ≥2.5 L/hari. Kurangi jeroan, kerang, daging merah, bir. Konsumsi vitamin C 500 mg/hari (turunkan asam urat). Kontrol berat badan, hindari puasa ekstrem.','ACR/EULAR Gout Guidelines 2020; EAU Guidelines on Metabolic Management 2024','https://www.rheumatology.org/Practice-Quality/Clinical-Guidelines/Gout'),
('uricAcid','en-US','Uric Acid','End product of purine metabolism — high levels cause gout and kidney stones.','Uric acid is produced from purine breakdown (compounds in meat, fish, alcohol). Kidneys excrete 70%. Excess (hyperuricemia) crystals in joints → gout, or in kidneys → uric acid stones. Gout prevalence 1–3% (EAU 2024).','Gout is often underdiagnosed. Chronic hyperuricemia also links to hypertension, metabolic syndrome, and chronic kidney disease (MEGA study, ARA 2020).','Fast 4 hours. Venous blood test or GCU point-of-care. Avoid high-purine foods 24 hours before test (organ meats, shellfish, beer). Drink adequate water 2L/day prior.','Males: <7 mg/dL; Females: <6 mg/dL (ACR/EULAR 2020)','mg/dL = milligrams of uric acid per deciliter of blood. Values >7 = supersaturation → monosodium urate crystals can form.','GCU (Sinocare)','sinocare','>7 mg/dL chronic: recurrent gout arthritis, tophi, uric acid kidney stones (10–25%). Gout: increased CKD and cardiovascular risk.','≥8 mg/dL + joint pain (especially big toe) → see rheumatologist. ≥9 mg/dL without symptoms: discuss urate-lowering therapy. Kidney stones + high uric acid: see urologist.','Drink ≥2.5 L water/day. Reduce organ meats, shellfish, red meat, beer. Take vitamin C 500 mg/day (lowers uric acid). Weight control, avoid extreme fasting.','ACR/EULAR Gout Guidelines 2020; EAU Guidelines on Metabolic Management 2024','https://www.rheumatology.org/Practice-Quality/Clinical-Guidelines/Gout');

