INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('bodyWeight','id-ID','Berat Badan','Massa total tubuh — dasar perhitungan BMI dan indikator risiko metabolik.','Berat badan mencakup massa lemak, otot, tulang, dan air. Fluktuasi harian 1–2 kg normal (cairan). Yang penting adalah tren jangka panjang dan komposisi (lemak vs otot). Obesitas (BMI ≥27 untuk Asia) mengobat 200+ kondisi medis (WHO).','Perubahan berat badan tak disadari bisa tanda penyakit serius: hipertiroidi, kanker, gagal jantung. Monitoring rutin mendeteksi tren naik/turun lebih awal.','Timbang di pagi hari setelah buang air, sebelum makan/siram. Pakai pakaian minimal. Timbangan di lantai datar/keras. Catat rata-rata mingguan, bukan harian.','Sesuai BMI 18.5–24.9 (umum) atau 18.5–22.9 (Asia-Pasifik, WHO 2000)','kg = kilogram massa tubuh. 1 kg ≈ 2.2 lbs. Fluktuasi harian normal: ±1–2 kg dari cairan, makanan, BAB.','Timbangan Digital','bodyScale','Obesitas (BMI ≥27 Asia): diabetes tipe 2, hipertensi, stroke, 13 jenis kanker, OA lutut, sleep apnea. Kurus (BMI <18.5): imun turun, osteoporosis.','Penurunan >5% dalam 6 bulan tanpa usaha → periksa ke dokter (tabs kanker/hipertiroidi). Kenaikan >5%/tahun → evaluasi diet dan aktivitas.','Makan sesuai porsi (metode piring: ½ sayur, ¼ protein, ¼ karbo). Catat berat mingguan. Olahraga 150 menit/minggu. Tidur 7–9 jam (kurang tidur = nafsu makan naik).','WHO Obesity Guidelines 2000; AHA Scientific Statement on Obesity 2023','https://www.who.int/news-room/fact-sheets/detail/obesity-and-overweight'),
('bodyWeight','en-US','Body Weight','Total body mass — the basis for BMI calculation and metabolic risk indicator.','Body weight includes fat, muscle, bone, and water mass. Daily fluctuation of 1–2 kg is normal (fluid). Important is long-term trend and composition (fat vs muscle). Obesity (BMI ≥27 for Asian) contributes to 200+ medical conditions (WHO).','Unintentional weight change can signal serious disease: hyperthyroidism, cancer, heart failure. Routine monitoring detects upward/downward trends earlier.','Weigh in the morning after bathroom, before eating/showering. Minimal clothing. Scale on hard flat floor. Track weekly average, not daily.','Per BMI 18.5–24.9 (general) or 18.5–22.9 (Asian-Pacific, WHO 2000)','kg = kilograms of body mass. 1 kg ≈ 2.2 lbs. Normal daily fluctuation: ±1–2 kg from fluid, food, bowel movement.','Digital Body Scale','bodyScale','Obesity (BMI ≥27 Asian): type 2 diabetes, hypertension, stroke, 13 cancer types, knee OA, sleep apnea. Underweight (BMI <18.5): weakened immunity, osteoporosis.','Loss >5% in 6 months without effort → see doctor (check cancer/hyperthyroidism). Gain >5%/year → evaluate diet and activity.','Eat proper portions (plate method: ½ vegetables, ¼ protein, ¼ carbs). Track weekly weight. Exercise 150 min/week. Sleep 7–9 hours (less sleep = increased appetite).','WHO Obesity Guidelines 2000; AHA Scientific Statement on Obesity 2023','https://www.who.int/news-room/fact-sheets/detail/obesity-and-overweight');

