INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('bmi','id-ID','BMI','Body Mass Index — rasio berat terhadap tinggi kuadrat sebagai indikator risiko metabolik.','BMI = berat (kg) ÷ tinggi² (m²). Tidak membedakan lemak dan otot — atlet bisa BMI tinggi tapi sehat. Klasifikasi Asia-Pasifik (WHO 2000): normal 18.5–22.9, overweight 23–24.9, obesitas ≥25. Untuk Indonesia, Kemenkes menggunakan ≥27 sebagai obesitas.','BMI adalah skrining cepat pertama — bukan diagnosis. Tapi BMI ≥27 (Asia) berkorelasi kuat dengan risiko diabetes 2, hipertensi, dan dislipidemia. Data Riskesdas: obesitas Indonesia 35.4%.','Ukur berat badan dan tinggi badan secara akurat. Tinggi: tanpa sepatu, berdiri tegak. Berat: pagi hari, pakaian minimal. BMI dihitung otomatis oleh aplikasi.','18.5–22.9 = normal (Asia); 23–24.9 = overweight; 25–29.9 = obesitas I; ≥30 = obesitas II (WHO Asia-Pasifik 2000)','kg/m² = kilogram per meter persegi. Contoh: berat 70 kg, tinggi 1.70 m → BMI = 70/(1.70)² = 24.2. Artinya, 24.2 kg massa tersebar di setiap m² permukaan tubuh.','Dihitung Otomatis','calculated','BMI ≥27: risiko diabetes 2, hipertensi, stroke, 13 kanker naik 2–3×. BMI <18.5: malnutrisi, imun turun, osteoporosis, anemia.','BMI ≥30 atau lingkar perut pria ≥90/wanita ≥80 → konsultasi dokter untuk evaluasi metabolik lengkap. BMI <17 → malnutrisi perlu intervensi.','Target berat realistis: turun 5–10% dari berat awal sudah bermakna klinis. Jangan diet ketat >1 kg/minggu. Fokus pola makan sehat jangka panjang, bukan diet kilat.','WHO Asia-Pacific BMI Classification 2000; Kemenkes RI Riskesdas 2023','https://www.who.int/publications/i/item/9241208943'),
('bmi','en-US','BMI','Body Mass Index — weight-to-height squared ratio as a metabolic risk indicator.','BMI = weight (kg) ÷ height² (m²). It does not distinguish fat from muscle — athletes can have high BMI while being healthy. Asian-Pacific classification (WHO 2000): normal 18.5–22.9, overweight 23–24.9, obesity ≥25.','BMI is a quick first screening — not a diagnosis. But BMI ≥27 (Asian) strongly correlates with diabetes 2, hypertension, and dyslipidemia risk. Data Riskesdas: Indonesia obesity 35.4%.','Accurately measure weight and height. Height: without shoes, standing straight. Weight: morning, minimal clothing. BMI calculated automatically by the app.','18.5–22.9 = normal (Asian); 23–24.9 = overweight; 25–29.9 = obesity I; ≥30 = obesity II (WHO Asia-Pacific 2000)','kg/m² = kilograms per square meter. Example: weight 70 kg, height 1.70 m → BMI = 70/(1.70)² = 24.2. This means 24.2 kg mass per m² of body surface.','Auto-calculated','calculated','BMI ≥27: type 2 diabetes, hypertension, stroke risk, 13 cancers 2–3× higher. BMI <18.5: malnutrition, weakened immunity, osteoporosis, anemia.','BMI ≥30 or waist circumference male ≥90/female ≥80 → see doctor for full metabolic evaluation. BMI <17 → malnutrition requiring intervention.','Realistic target: losing 5–10% of initial weight is clinically meaningful. Don''t crash diet >1 kg/week. Focus on long-term healthy eating, not quick diets.','WHO Asia-Pacific BMI Classification 2000; Kemenkes RI Riskesdas 2023','https://www.who.int/publications/i/item/9241208943');

