-- waistCircumference
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('waistCircumference','id-ID','Lingkar Perut','Ukuran lemak viseral di perut — prediktor risiko metabolik independen dari BMI.','Lingkar perut mengukur lemak di rongga perut (viseral). Lemak viseral lebih berbahaya dari lemak bawah kulit — aktif melepaskan sitokin inflamasi yang menyebabkan resistensi insulin, hipertensi, dan dislipidemia. IDF 2023: lingkar perut adalah komponen wajib diagnosis metabolik syndrome.','Banyak orang BMI normal tapi lingkar perut besar (normal weight obesity). Risiko metabolik tinggi = lingkar perut besar, BUKAN sekadar BMI tinggi. IDF 2023 menetapkan cutoff Asia: pria ≥90, wanita ≥80.','Berdiri tegak, perut rileks (jangan kempeskan). Meteran di titik tengah antara tulang rusuk terbawah dan puncak tulang pinggang (iliac crest). Ukur di akhir napas normal. Jangan kencangkan meteran.','Pria <90 cm, Wanita <80 cm (IDF Asia 2023). Pria ≥90, Wanita ≥80 = risiko metabolik tinggi.','cm = sentimeter keliling perut pada titik tengah antara iga terakhir dan tulang pinggang. Mengukur lemak intra-abdominal, bukan lemak kulit.','Meteran','manual','Lingkar perut ≥90 (pria)/≥80 (wanita): 3× risiko diabetes tipe 2, 2× risiko hipertensi. MetS: risiko kardiovaskular 2–3× lipat.','Lingkar perut ≥100 (pria)/≥90 (wanita) → evaluasi代谢 syndrome lengkap (gula darah, lipid, tekanan darah). Kombinasi BMI ≥23 + perut besar → risiko sangat tinggi.','Kurangi gula fruktosa (minuman manis, sirup) — paling mudah disimpan sebagai lemak viseral. Olahraga aerobik 150 menit/minggu membakar lemak viseral. Latihan bebas beban tidak cukup — butuh kardio.','IDF Consensus Worldwide Definition of Metabolic Syndrome 2023; WHO','https://www.idf.org/e-library/consensus-statements/60-idfconsensus-worldwide-definitionof-the-metabolic-syndrome'),
('waistCircumference','en-US','Waist Circumference','Measures visceral fat in the abdomen — an independent metabolic risk predictor from BMI.','Waist circumference measures fat in the abdominal cavity (visceral). Visceral fat is more dangerous than subcutaneous fat — it actively releases inflammatory cytokines causing insulin resistance, hypertension, and dyslipidemia. IDF 2023: waist circumference is mandatory for metabolic syndrome diagnosis.','Many people have normal BMI but large waist (normal weight obesity). High metabolic risk = large waist, NOT just high BMI. IDF 2023 sets Asian cutoffs: male ≥90, female ≥80.','Stand straight, abdomen relaxed (do not suck in). Tape at midpoint between lowest rib and top of hip bone (iliac crest). Measure at end of normal exhale. Do not pull tape tight.','Male <90 cm, Female <80 cm (IDF Asia 2023). Male ≥90, Female ≥80 = high metabolic risk.','cm = centimeters of waist circumference at the midpoint between the lowest rib and hip bone. Measures intra-abdominal fat, not skin fat.','Measuring Tape','manual','Waist ≥90 (male)/≥80 (female): 3× type 2 diabetes risk, 2× hypertension risk. MetS: 2–3× cardiovascular risk.','Waist ≥100 (male)/≥90 (female) → full metabolic syndrome evaluation (glucose, lipids, blood pressure). BMI ≥23 + large waist → very high risk.','Reduce fructose sugar (sugary drinks, syrup) — most easily stored as visceral fat. Aerobic exercise 150 min/week burns visceral fat. Weight training alone is not enough — cardio needed.','IDF Consensus Worldwide Definition of Metabolic Syndrome 2023; WHO','https://www.idf.org/e-library/consensus-statements/60-idfconsensus-worldwide-definitionof-the-metabolic-syndrome');

