-- bodyTemperature
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('bodyTemperature','id-ID','Suhu Tubuh','Suhu inti tubuh — indikator infeksi, inflamasi, dan status metabolik.','Suhu inti diatur oleh hipotalamus pada set point ~37°C. Demam (≥37.5°C aksila atau ≥38.0°C rektal) = tanda pertahanan tubuh melawan infeksi. Hipotermia (<35°C) = darurat medis. Fluktuasi harian 0.5°C normal (pagi rendah, sore tinggi).','Demam adalah tanda paling sensitif dari infeksi sistemik. Dalam konteks pasca-bedah atau imunokompromai, demam ringan sudah bisa tanda sepsis. Hipotermia pada lansia bisa tandanya hipotiroidi atau sepsis.','Termometer digital di ketiak: 5 menit, lengan rapat ke tubuh. Termometer telingan: tarik daun telinga ke atas-belakang (dewasa). Hindari ukur setelah mandi/berolahraga (tunggu 30 menit). Jangan ukur setelah minum panas/dingin.','36.1–37.2°C (ketiak); 36.5–37.5°C (rektal). Demam: ≥37.5°C (ketiak) atau ≥38.0°C (rektal).','°C = derajat Celsius. 37°C = set point normal hipotalamus. 1°C di atas normal = demam ringan; 2°C = demam sedang; >3°C = demam tinggi.','Termometer Digital','thermometer','Demam berkepanjangan: infeksi kronis (TB, endokarditis), malignansi, penyakit autoimun. >40°C: risiko kejang demam (anak), kerusakan protein. <35°C: aritmia, gagal organ.','≥39.5°C (dewasa) atau ≥40°C (anak) → segera ke IGD. Demam >3 hari tanpa sebab jelas → dokter. <35°C → IGD. Demam + leher kaku + ruam → IGD (septikemia/meningitis).','Istirahat cukup saat demam. Minum air ≥2.5 L/hari. Kompres hangat (bukan dingin) untuk menurunkan demam. Jangan pakai paracetamol jika demam <38.5°C tanpa ketidaknyamanan.','Mayo Clinic Body Temperature; WHO Clinical Management of Severe Infection 2022','https://www.mayoclinic.org/tests-procedures/thermometry/about/pac-20391972'),
('bodyTemperature','en-US','Body Temperature','Core body temperature — indicator of infection, inflammation, and metabolic status.','Core temperature is regulated by the hypothalamus at a set point of ~37°C. Fever (≥37.5°C axillary or ≥38.0°C rectal) = sign that the body is fighting infection. Hypothermia (<35°C) = medical emergency. Daily fluctuation of 0.5°C is normal (lower in morning, higher in evening).','Fever is the most sensitive sign of systemic infection. In post-surgical or immunocompromised patients, even mild fever can indicate sepsis. Hypothermia in elderly may indicate hypothyroidism or sepsis.','Digital thermometer in armpit: 5 minutes, arm close to body. Ear thermometer: pull ear upward-backward (adults). Avoid measuring after bathing/exercise (wait 30 min). Don''t measure after drinking hot/cold fluids.','36.1–37.2°C (axillary); 36.5–37.5°C (rectal). Fever: ≥37.5°C (axillary) or ≥38.0°C (rectal).','°C = degrees Celsius. 37°C = normal hypothalamic set point. 1°C above normal = low-grade fever; 2°C = moderate; >3°C = high fever.','Digital Thermometer','thermometer','Prolonged fever: chronic infections (TB, endocarditis), malignancy, autoimmune disease. >40°C: febrile seizure risk (children), protein damage. <35°C: arrhythmia, organ failure.','≥39.5°C (adults) or ≥40°C (children) → go to ER immediately. Fever >3 days without clear cause → see doctor. <35°C → ER. Fever + stiff neck + rash → ER (septicemia/meningitis).','Rest adequately during fever. Drink ≥2.5 L water/day. Warm (not cold) compress to reduce fever. Avoid paracetamol if fever <38.5°C without discomfort.','Mayo Clinic Body Temperature; WHO Clinical Management of Severe Infection 2022','https://www.mayoclinic.org/tests-procedures/thermometry/about/pac-20391972');

-- ============================================================
-- sleepDuration
-- ============================================================
INSERT INTO HL_medicalTermPopups (termCode,locale,label,shortDef,fullDef,whyMeasure,howToMeasure,normalRange,unitExplanation,deviceName,deviceTypeCode,risksIfAbnormal,whenToSeeDoctor,preventionTip,sourceName,sourceUrl) VALUES
('sleepDuration','id-ID','Durasi Tidur','Lamanya tidur per malam — pilar kesehatan seiring nutrisi dan olahraga.','Durasi tidur mengukur total waktu tidur nyata (bukan waktu di tempat tidur). Tidur <7 jam kronis: 26% risiko kematian lebih tinggi, 33% lebih banyak pilek (Cohen 2009), 48% lebih banyak penyakit jantung (AHA 2023). AASM 2023 merekomendasikan 7–9 jam untuk dewasa.','Tidur pendek kronis = faktor risiko independen untuk obesitas, diabetes tipe 2, hipertensi, depresi, dan kanker. Konsensus AASM 2023: tidur cukup = vital sign ke-5 selain tekanan darah, nadi, suhu, dan pernapasan.','Catat waktu tidur dan bangun aktual (bukan waktu tidur dan bangun di tempat tidur). Gunakan sleep tracker jika tersedia. Rata-rata 7 hari lebih akurat dari 1 malam. Hindari kafein 6 jam sebelum tidur.','7–9 jam per malam (dewasa 18–64); 7–8 jam (≥65 tahun) — AASM/AHA 2023','jam = durasi tidur aktual dalam jam. Bukan waktu di tempat tidur. 7.5 jam artinya tertidur 7 jam 30 menit (bukan 7 jam 30 menit di kasur).','Sleep Tracker','sleepTracker','<6 jam kronis: obesitas 55%, diabetes 28%, hipertensi 33%, depresi 2× lipat. >9 jam kronis: bisa tandanya sleep apnea, depresi, hipotiroidi.','Insomnia >3 malam/minggu selama >3 bulan → konsultasi dokter tidur. Mendengkur keras + kantuk siang → skrining sleep apnea. Bangun terengah-engah → IGD jika berulang.','Tidur bangun pada jam sama setiap hari (termasuk weekend). Kamar gelap, sejuk (18–20°C), tenang. Layar off 30–60 menit sebelum tidur (cahaya biru). Caffeine cutoff 14.00.','AASM Sleep Duration Recommendations 2023; AHA Life''s Essential 8 2023','https://aasm.org/clinical-resources/sleep-duration-recommendations/'),
('sleepDuration','en-US','Sleep Duration','Length of sleep per night — a health pillar on par with nutrition and exercise.','Sleep duration measures actual sleep time (not time in bed). Chronic short sleep <7hr: 26% higher mortality, 33% more colds (Cohen 2009), 48% more heart disease (AHA 2023). AASM 2023 recommends 7–9 hours for adults.','Chronic short sleep = independent risk factor for obesity, type 2 diabetes, hypertension, depression, and cancer. AASM 2023 consensus: adequate sleep = 5th vital sign alongside BP, pulse, temperature, and respiration.','Record actual sleep and wake times (not time in bed asleep). Use sleep tracker if available. 7-day average is more accurate than 1 night. Avoid caffeine 6 hours before sleep.','7–9 hours per night (adults 18–64); 7–8 hours (≥65 years) — AASM/AHA 2023','hours = actual sleep duration in hours. Not time in bed. 7.5 hours means asleep for 7 hours 30 minutes (not in bed for 7h30m).','Sleep Tracker','sleepTracker','<6 hours chronic: obesity 55%, diabetes 28%, hypertension 33%, depression 2×. >9 hours chronic: may indicate sleep apnea, depression, hypothyroidism.','Insomnia >3 nights/week for >3 months → consult sleep doctor. Loud snoring + daytime sleepiness → screen for sleep apnea. Waking gasping → ER if recurrent.','Same sleep/wake time every day (including weekends). Dark, cool (18–20°C), quiet room. Screens off 30–60 min before sleep (blue light). Caffeine cutoff at 2 PM.','AASM Sleep Duration Recommendations 2023; AHA Life''s Essential 8 2023','https://aasm.org/clinical-resources/sleep-duration-recommendations/');
